module top_module(
  input clk,
  input reset,
  input signed [31:0] input_data,
  output reg signed [31:0] output_data,
  output reg valid
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset) begin
      output_data <= 0;
      valid <= 0;
    end else begin
      if (input_data >= 0) begin
        output_data <= input_data + 1;
        valid <= 1;
      end else begin
        output_data <= input_data - 1;
        valid <= 1;
      end
    end
  end

endmodule
